import React, { useState, useEffect, useMemo } from 'react';
import {
  CButton,
  CModal,
  CModalHeader,
  CModalTitle,
  CModalBody,
  CModalFooter,
  CForm,
  CCol,
  CFormLabel,
  CFormFeedback,
  CFormInput,
  CFormCheck,
} from '@coreui/react';
import CIcon from '@coreui/icons-react';
import { cilPen, cilPlus } from '@coreui/icons';
import PropTypes from 'prop-types';
import { settingsUnavailabilities } from 'src/services/standardUsers/index';
import i18n from 'src/i18n';

const initialState = {
  start_time: '',
  end_time: '',
  start_date: '',
  end_date: '',
  all_days: false,
  monday: false,
  tuesday: false,
  wednesday: false,
  thursday: false,
  friday: false,
  saturday: false,
  sunday: false,
  force_allowed: false,
};

const UnavailabilitiesC = ({ refresh, selectedUnavailabilities }) => {
  const [visible, setVisible] = useState(false);
  const [validated, setValidated] = useState(false);
  const [isUpdateMode, setIsUpdateMode] = useState(false);
  const [formData, setFormData] = useState(initialState);

  useEffect(() => {
    setIsUpdateMode(!!selectedUnavailabilities);
    setFormData(selectedUnavailabilities || initialState);
  }, [selectedUnavailabilities]);

  const handleAddOrUpdate = async () => {
    const result = isUpdateMode
      ? await settingsUnavailabilities.updateunavailabilities(formData, formData.id)
      : await settingsUnavailabilities.addunavailabilities(formData);

    if (result) {
      setVisible(false);
      setValidated(false);
      setIsUpdateMode(false);
      setFormData(initialState);
      refresh();
    }
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    const form = event.currentTarget;

    if (!form.checkValidity()) {
      event.stopPropagation();
    }

    setValidated(true);

    if (form.checkValidity()) {
      handleAddOrUpdate();
    }
  };

  const modalTitle = useMemo(() => (
    isUpdateMode ? i18n.t('updateUnavailabilitiesTitle') : i18n.t('addUnavailabilitiesTitle')
  ), [isUpdateMode]);

  const handleChange = (key, value) => {
    setFormData((prev) => ({ ...prev, [key]: value }));
  };

  const renderCheckbox = (key, label) => (
    <CFormCheck
      id={`check-${key}`}
      label={label}
      checked={!!formData[key]}
      onChange={(e) => handleChange(key, e.target.checked)}
    />
  );

  return (
    <>
      <CButton color={isUpdateMode ? 'secondary' : 'primary'} onClick={() => setVisible(true)}>
        <CIcon icon={isUpdateMode ? cilPen : cilPlus} />
      </CButton>

      <CModal alignment="center" visible={visible} onClose={() => setVisible(false)} size="xl">
        <CModalHeader onClose={() => setVisible(false)}>
          <CModalTitle>{modalTitle}</CModalTitle>
        </CModalHeader>
        <CModalBody>
          <CForm className="row g-3 needs-validation" noValidate validated={validated} onSubmit={handleSubmit}>
            <CCol md={6}>
              <CFormLabel htmlFor="startTime">{i18n.t('startTime')}</CFormLabel>
              <CFormInput
                type="time"
                id="startTime"
                value={formData.start_time}
                onChange={(e) => handleChange('start_time', e.target.value)}
                required
              />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>

            <CCol md={6}>
              <CFormLabel htmlFor="endTime">{i18n.t('endTime')}</CFormLabel>
              <CFormInput
                type="time"
                id="endTime"
                value={formData.end_time}
                onChange={(e) => handleChange('end_time', e.target.value)}
                required
              />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>

            <CCol md={6}>
              <CFormLabel htmlFor="startDate">{i18n.t('startDate')}</CFormLabel>
              <CFormInput
                type="date"
                id="startDate"
                value={formData.start_date}
                onChange={(e) => handleChange('start_date', e.target.value)}
                required
              />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>

            <CCol md={6}>
              <CFormLabel htmlFor="endDate">{i18n.t('endDate')}</CFormLabel>
              <CFormInput
                type="date"
                id="endDate"
                value={formData.end_date}
                onChange={(e) => handleChange('end_date', e.target.value)}
                required
              />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>

            <CCol md={12}>
              <h6>{i18n.t('daysSelection')}</h6>
              {renderCheckbox('all_days', i18n.t('allDays'))}
              <div className="d-flex flex-wrap gap-3 mt-2">
                {renderCheckbox('monday', i18n.t('monday'))}
                {renderCheckbox('tuesday', i18n.t('tuesday'))}
                {renderCheckbox('wednesday', i18n.t('wednesday'))}
                {renderCheckbox('thursday', i18n.t('thursday'))}
                {renderCheckbox('friday', i18n.t('friday'))}
                {renderCheckbox('saturday', i18n.t('saturday'))}
                {renderCheckbox('sunday', i18n.t('sunday'))}
              </div>
            </CCol>

            <CCol md={12}>
              {renderCheckbox('force_allowed', i18n.t('forceAllowed'))}
            </CCol>

            <CModalFooter>
              <CButton color="secondary" onClick={() => setVisible(false)}>{i18n.t('closeButton')}</CButton>
              <CButton color="primary" type="submit">{i18n.t('saveButton')}</CButton>
            </CModalFooter>
          </CForm>
        </CModalBody>
      </CModal>
    </>
  );
};

UnavailabilitiesC.propTypes = {
  refresh: PropTypes.func.isRequired,
  selectedUnavailabilities: PropTypes.object,
};

export default UnavailabilitiesC;
