
import React, { useEffect, useState } from 'react';
import {
    CRow,
    CCol,
    CCard,
    CCardHeader,
    CCardBody,
} from '@coreui/react';
import { settingsUnavailabilities } from 'src/services/standardUsers/index';
import GenericTable from 'src/components/Generic.Table';
import UnavailabilitiesC from './Unavailabilities'
import i18n from 'src/i18n';
const Unavailabilities = () => {
    const [List, setList] = useState([]);

    const fetchUnavailabilities = async () => {
        try {
            const list = await settingsUnavailabilities.getunavailabilities();
            if (list) {
                setList(list?.data);
            }
        } catch (error) {
            console.error('Error fetching admin list:', error);
        }
    };
    useEffect(() => {
        fetchUnavailabilities();
    }, []);

    const columns = [
        { label: '#', field: 'index' },
        { label: i18n.t('startTime'), field: 'start_time' },
        { label: i18n.t('endTime'), field: 'end_time' },
        { label: i18n.t('startDate'), field: 'start_date' },
        { label: i18n.t('endDate'), field: 'end_date' },
        { label: i18n.t('allDays'), field: 'all_days', render: (item) => item.all_days ? '✔️' : '❌' },

        // Colonnes pour les jours spécifiques
        { label: i18n.t('monday'), field: 'monday', render: (item) => item.monday ? '✔️' : '❌' },
        { label: i18n.t('tuesday'), field: 'tuesday', render: (item) => item.tuesday ? '✔️' : '❌' },
        { label: i18n.t('wednesday'), field: 'wednesday', render: (item) => item.wednesday ? '✔️' : '❌' },
        { label: i18n.t('thursday'), field: 'thursday', render: (item) => item.thursday ? '✔️' : '❌' },
        { label: i18n.t('friday'), field: 'friday', render: (item) => item.friday ? '✔️' : '❌' },
        { label: i18n.t('saturday'), field: 'saturday', render: (item) => item.saturday ? '✔️' : '❌' },
        { label: i18n.t('sunday'), field: 'sunday', render: (item) => item.sunday ? '✔️' : '❌' },
        {
            label: i18n.t('actionLabel'),
            field: 'actions',
            render: (item) => <UnavailabilitiesC refresh={() => fetchUnavailabilities()} selectedUnavailabilities={item} />,
        },
    ];

    return (
        <CCard className="mb-4">
            <CCardHeader>
                <CRow className="align-items-center">
                    <CCol md="6" xs="12">
                        <strong>   {i18n.t('UnavailabilitiesTableTitle')}</strong>
                    </CCol>
                    <CCol md="6" xs="12" className="text-md-end mt-md-0 mt-3">
                        <UnavailabilitiesC refresh={() => fetchUnavailabilities()} />
                    </CCol>
                </CRow>
            </CCardHeader>
            <CCardBody>
                <CRow>
                    <CCol xs="12">
                        <CCard className="mb-4">
                            <CCardHeader>
                                <strong>{i18n.t('UnavailabilitiesList')}</strong>
                            </CCardHeader>
                            <CCardBody>
                                <GenericTable columns={columns} data={List} />
                            </CCardBody>
                        </CCard>
                    </CCol>
                </CRow>
            </CCardBody>
        </CCard>
    );
};

export default Unavailabilities;

